121	        assert_eq!(Config::new(0, 0), Err(Error::MaxValuePower));
122	        assert_eq!(Config::new(0, 65), Err(Error::MaxValuePower));
123	        assert_eq!(Config::new(4, 4), Err(Error::GroupingPower));
