1	//! The borrowed-storage histogram and its record path.
2	//!
3	//! - `Histogram` borrows its counts slice from the caller
4	//!   (static buffer, stack array, or heap under `std`), so
5	//!   storage stays detachable — the future buffer-swap
6	//!   servicing model needs exactly that.
7	//! - `record` is the one hot operation: index (a compare, a
8	//!   clz, two shifts) and a saturating increment. No floats,
9	//!   no allocation, no panics.
10	
11	use crate::analysis::{Buckets, merge_into, quantile_of};
12	use crate::config::{Config, Error};
13	use crate::counter::Counter;
14	
15	/// Shared record-path core for the borrowed and owned types:
16	/// index `value`, saturating-add `n` into its bucket, bump
17	/// `total`. The `get_mut` guard makes the panic path
18	/// unreachable (index invariant proven by the config tests).
19	#[inline]
20	pub(crate) fn record_into<C: Counter>(
21	    config: &Config,
22	    counts: &mut [C],
23	    total: &mut u64,
24	    value: u64,
25	    n: u64,
26	) {
27	    let idx = config.index_for(value);
28	    if let Some(c) = counts.get_mut(idx) {
29	        *c = c.sat_add(n);
30	        *total = total.saturating_add(n);
31	    }
32	}
33	
34	/// A log-linear histogram over caller-supplied counts storage.
35	///
36	/// - `config` — the h2 powers and index math.
37	/// - `counts` — exactly `config.total_buckets()` counters.
38	/// - `total` — saturating sum of all recorded counts (u64),
39	///   maintained on the record path for O(1) rank math later.
40	#[derive(Debug)]
41	pub struct Histogram<'a, C: Counter = u32> {
42	    config: Config,
43	    total: u64,
44	    counts: &'a mut [C],
45	}
46	
47	impl<'a, C: Counter> Histogram<'a, C> {
48	    /// Bind a config to its counts storage.
49	    ///
50	    /// - `counts.len()` must equal `config.total_buckets()`
51	    ///   ([`Error::StorageLen`] otherwise).
52	    /// - Storage is not zeroed here: pre-zeroed storage (or a
53	    ///   reused slice from a previous run) is the caller's
54	    ///   contract; `total` is recomputed from the counts so a
55	    ///   handed-back slice stays consistent.
56	    pub fn new(config: Config, counts: &'a mut [C]) -> Result<Self, Error> {
57	        if counts.len() != config.total_buckets() {
58	            return Err(Error::StorageLen);
59	        }
60	        let mut total = 0u64;
61	        for c in counts.iter() {
62	            total = total.saturating_add(c.to_u64());
63	        }
64	        Ok(Histogram {
65	            config,
66	            total,
67	            counts,
68	        })
69	    }
70	
71	    /// The config this histogram was built with.
72	    pub fn config(&self) -> Config {
73	        self.config
74	    }
75	
76	    /// Saturating sum of all recorded counts.
77	    pub fn total(&self) -> u64 {
78	        self.total
79	    }
80	
81	    /// Record one occurrence of `value`. O(1), never panics;
82	    /// over-range values clamp into the top bucket and a full
83	    /// counter saturates.
84	    #[inline]
85	    pub fn record(&mut self, value: u64) {
86	        self.record_n(value, 1);
87	    }
88	
89	    /// Record `n` occurrences of `value`; same semantics as
90	    /// [`record`](Histogram::record).
91	    #[inline]
92	    pub fn record_n(&mut self, value: u64, n: u64) {
93	        record_into(&self.config, self.counts, &mut self.total, value, n);
94	    }
95	
96	    /// Count in bucket `index`, widened to u64; `None` past
97	    /// the last bucket.
98	    pub fn count_at(&self, index: usize) -> Option<u64> {
99	        self.counts.get(index).map(|c| c.to_u64())
100	    }
101	
102	    /// Release the borrow and hand the counts slice back —
103	    /// the swap-model hand-off shape.
104	    pub fn into_counts(self) -> &'a mut [C] {
105	        self.counts
106	    }
107	
108	    /// Iterate every bucket lowest-first, with cumulative
109	    /// counts (the band-table building block).
110	    pub fn buckets(&self) -> Buckets<'_, C> {
111	        Buckets::new(self.config, self.counts)
112	    }
113	
114	    /// Value at quantile `q` in `[0.0, 1.0]`: the upper
115	    /// bound of the bucket holding the rank-`ceil(q·total)`
116	    /// value (hdrhistogram's highest-equivalent convention,
117	    /// one-sided error ≤ 2⁻ᵍ). `None` when empty or `q` is
118	    /// out of range (NaN included).
119	    pub fn quantile(&self, q: f64) -> Option<u64> {
120	        quantile_of(&self.config, self.counts, self.total, q)
121	    }
122	
123	    /// Merge `other`'s counts into `self` (saturating);
